package org.jsoup.helper;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.helper.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.helper.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.And;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.parser.Parser;
import org.jsoup.helper.W3CDom;
import org.w3c.dom.Node;

import static org.junit.Assert.*;

public class StepDefs {
    private Document jsoupDoc;
    private String htmlContent;
    private boolean isNamespaceDeclared;
    private org.w3c.dom.Document w3cDoc;
    private org.w3c.dom.Element w3cElement;

    @Given("I have a Jsoup Document containing the HTML {string}")
    public void i_have_a_Jsoup_Document_containing_the_HTML(String html) {
        this.htmlContent = html;
        this.jsoupDoc = Jsoup.parse(html);
    }

    @And("the namespace prefix {string} is not declared in the document")
    public String namespacePrefix) {
        this.isNamespaceDeclared = false; // Marking that the namespace is not declared
    }

    @When("I convert the Jsoup Document to a W3C DOM Document")
    public void i_convert_the_Jsoup_Document_to_a_W3C_DOM_Document() {
        try {
            W3CDom w3cDom = new W3CDom();
            this.w3cDoc = w3cDom.fromJsoup(jsoupDoc);

            // Find the element that matches the pattern of the original HTML
            // Since we know it starts with a namespace, we look for the element
            org.jsoup.nodes.Element element = jsoupDoc.select("*[namespace*=:]").first(); // This would select elements with namespaces
            if (element == null) {
                element = jsoupDoc.select("*").first(); // Fallback to first element
            }

            // For the specific case of "<fb:like>One</fb:like>", we'd be looking for an element named fb:like
            String[] parts = htmlContent.replaceAll("[<>]", "").split(">");
            String elementTag = parts[0];
            if (elementTag.contains(" ")) {
                elementTag = elementTag.split(" ")[0]; // Get just the tag name
            }

            // Look for an element that matches the expected tag in the root
            if (w3cDoc != null && w3cDoc.getDocumentElement() != null) {
                this.w3cElement = w3cDoc.getDocumentElement();
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    @Then("the converted W3C Element for {string} should be created successfully")
    public void the_converted_W3C_Element_for_should_be_created_successfully(String elementName) {
        assertNotNull("W3C Element should be created successfully", w3cElement);
    }

    @And("the W3C Element should have a Node Name of {string}")
    public void the_W3C_Element_should_have_a_Node_Name_of(String nodeName) {
        assertEquals("W3C Element should have the correct node name", nodeName, w3cElement.getNodeName());
    }

    @And("the W3C Element should have a Local Name of {string}")
    public void the_W3C_Element_should_have_a_Local_Name_of(String localName) {
        assertEquals("W3C Element should have the correct local name", localName, w3cElement.getLocalName());
    }

    @And("the W3C Element should have a null Namespace URI")
    public void the_W3C_Element_should_have_a_null_Namespace_URI() {
        assertNull("W3C Element should have a null namespace URI", w3cElement.getNamespaceURI());
    }
}

