@When("I convert the Jsoup Document to a W3C DOM Document")
public void i_convert_the_Jsoup_Document_to_a_W3C_DOM_Document() {
    try {
        W3CDom w3cDom = new W3CDom();
        this.w3cDoc = w3cDom.fromJsoup(jsoupDoc);

        // Get the tag name from the HTML content (e.g., from "<fb:like>One</fb:like>", get "fb:like")
        String tagContent = htmlContent.replaceAll("^<([^>]+)>.*", "$1"); // Extract content inside <>
        if (tagContent.contains(" ")) {
            tagContent = tagContent.split(" ")[0]; // If there are attributes, just get the tag name
        }

        // Look for the element with the specific tag name in the W3C DOM
        if (w3cDoc != null) {
            this.w3cElement = w3cDoc.getDocumentElement();
            // If the document element doesn't match our expected tag, search more specifically
            if (w3cElement != null && !w3cElement.getNodeName().equals(tagContent)) {
                // Search for the element by tag name in the document
                org.w3c.dom.NodeList nodeList = w3cDoc.getElementsByTagName("*");
                for (int i = 0; i < nodeList.getLength(); i++) {
                    org.w3c.dom.Node node = nodeList.item(i);
                    if (node.getNodeName().equals(tagContent)) {
                        this.w3cElement = (org.w3c.dom.Element) node;
                        break;
                    }
                }
            }
        }
    } catch (Exception e) {
        e.printStackTrace();
    }
}

